Real64 CalcMoWITTWindward(Real64 const DeltaTemp, Real64 const WindAtZ)
{
    Real64 Hn = CalcMoWITTNatural(DeltaTemp);
    Real64 Hf = CalcMoWITTForcedWindward(WindAtZ);
    return std::sqrt(pow_2(Hn) + pow_2(Hf));
